() => {
  window.__sfFlowTestReady = false;
  const banner = document.createElement('div');
  banner.id = '__sf-flow-test-banner';
  banner.textContent = '请进入需要测试的画面，然后按 F2';
  banner.style.cssText = 'position:fixed;z-index:2147483647;left:16px;top:16px;padding:10px 14px;background:#172b4d;color:white;border-radius:6px;font:14px sans-serif;box-shadow:0 2px 8px #555';
  document.body.appendChild(banner);
  const ready = (event) => {
    if (event.key !== 'F2') return;
    event.preventDefault();
    window.__sfFlowTestReady = true;
    banner.remove();
    document.removeEventListener('keydown', ready, true);
  };
  document.addEventListener('keydown', ready, true);
}
